code.C:
#include <stdio.h>
void rotate(int* nums, int numsSize) {
    int temp = nums[0];
    for (int i = 0; i < numsSize - 1; i++) {
        nums[i] = nums[i + 1];
    }
    nums[numsSize - 1] = temp;
}

